#!/usr/bin/env bash
# finetune_b.sh — Fine-tune each module-ablation A-ckpt on Dataset-B.
#
# For each variant: load <variant>'s A-ckpt → fine-tune on B with the
# variant's B-loss config (already generated by make_config.py during A).
#
# Run from /workspace/CAP/:
#     bash eval/ablation/module/finetune_b.sh
#
# Override:
#     VARIANTS="no_physics" SEED=0 bash eval/ablation/module/finetune_b.sh

set -euo pipefail

VARIANTS="${VARIANTS:-no_hier no_algebraic no_cvae no_physics no_equivariance no_lipschitz}"
SEED="${SEED:-0}"
MAX_EPOCHS="${MAX_EPOCHS:-}"
BATCH_SIZE="${BATCH_SIZE:-8}"
NUM_WORKERS="${NUM_WORKERS:-4}"
NPROC_PER_NODE="${NPROC_PER_NODE:-8}"
MASTER_PORT="${MASTER_PORT:-29502}"        # different port from train_a.sh

MANIFEST="${MANIFEST:-dataset/dataset_b/manifest.json}"
DATA_DIR="${DATA_DIR:-dataset/dataset_b/data}"

CFG_ROOT="${CFG_ROOT:-configs/_ablation_module}"
RUN_ROOT="${RUN_ROOT:-runs/module}"

if [[ ! -d configs ]] || [[ ! -d train ]] || [[ ! -d eval ]]; then
    echo "ERROR: run from CAP root. cwd=$(pwd)"
    exit 1
fi

find . -name "__pycache__" -type d -exec rm -rf {} + 2>/dev/null || true
find . -name "*.pyc" -delete 2>/dev/null || true

for V in $VARIANTS; do
    A_CKPT="${RUN_ROOT}/${V}/seed_${SEED}/ckpt/main_exp_final.pt"
    OUT_DIR="${RUN_ROOT}/${V}/seed_${SEED}/finetune_b"
    CFG_DIR="${CFG_ROOT}/${V}"
    LOG="${OUT_DIR}/finetune_b.log"

    if [[ ! -f "$A_CKPT" ]]; then
        echo "  [${V}] WARN: A ckpt missing ($A_CKPT) — run train_a.sh first; skipping"
        continue
    fi
    if [[ -f "${OUT_DIR}/ckpt/main_exp_final.pt" ]]; then
        echo "  [${V}] B ckpt exists, skipping"
        continue
    fi
    if [[ ! -f "${CFG_DIR}/config.yaml" ]] || [[ ! -f "${CFG_DIR}/loss_b.yaml" ]]; then
        echo "  [${V}] WARN: variant configs missing in ${CFG_DIR} — re-run make_config.py; skipping"
        continue
    fi

    echo ""
    echo "═══════════════════════════════════════════════════════════════════"
    echo "  B fine-tune  variant=${V}  seed=${SEED}"
    echo "    A ckpt: $A_CKPT"
    echo "    out   : $OUT_DIR"
    echo "═══════════════════════════════════════════════════════════════════"

    EXTRA_FLAGS=()
    if [[ -s "${CFG_DIR}/trainer_flags.txt" ]]; then
        while IFS= read -r line; do
            [[ -n "$line" ]] && EXTRA_FLAGS+=("$line")
        done < "${CFG_DIR}/trainer_flags.txt"
    fi
    if [[ -n "$MAX_EPOCHS" ]]; then
        EXTRA_FLAGS+=(--max-epochs "$MAX_EPOCHS")
    fi

    mkdir -p "$OUT_DIR"

    torchrun --nproc_per_node="$NPROC_PER_NODE" --master_port="$MASTER_PORT" \
        -m train.trainer \
        --config            "${CFG_DIR}/config.yaml" \
        --loss-config       "${CFG_DIR}/loss_b.yaml" \
        --stages-preset     b \
        --resume-from-ckpt  "$A_CKPT" \
        --dataset           b \
        --manifest          "$MANIFEST" \
        --data-dir          "$DATA_DIR" \
        --batch-size        "$BATCH_SIZE" \
        --num-workers       "$NUM_WORKERS" \
        --out-dir           "$OUT_DIR" \
        --seed              "$SEED" \
        --save-every        50 \
        --keep-last         1 \
        "${EXTRA_FLAGS[@]}" \
        2>&1 | tee "$LOG"

    echo "  ✔ ${V} B done. ckpt: ${OUT_DIR}/ckpt/main_exp_final.pt"
done

echo ""
echo "═══════════════════════════════════════════════════════════════════"
echo "  All B-side fine-tunes done."
echo "  Next: bash eval/ablation/module/eval_all.sh"
echo "═══════════════════════════════════════════════════════════════════"
